import React, { useEffect, useState } from "react";
import API from "../Api/axios";

const ProductsCard = ({ logout }) => {
  const [products, setProducts] = useState([]);

  const fetchProducts = async () => {
    try {
      const res = await API.get("/products");
      setProducts(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const saveProduct = async (id) => {
    try {
      await API.post("/users/products/add", { productId: id });
      alert("Product saved to your list");
    } catch (err) {
      alert(err.response?.data?.message || "Failed");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Products</h2>

      <button onClick={logout}>Logout</button>

      <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginTop: 16 }}>
        {products.map((p) => (
          <div key={p._id} style={{ border: "1px solid #ddd", padding: 12, width: 220 }}>
            {p.image && (
              <img src={p.image} alt={p.name} style={{ width: "100%", height: 120, objectFit: "cover" }} />
            )}

            <h4>{p.name}</h4>
            <p>₹{p.price}</p>
            {p.info && <p style={{ fontSize: 13 }}>{p.info}</p>}

            <button onClick={() => saveProduct(p._id)}>Add to My Products</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductsCard;
